1050→  // ============================================================
1051→  // CONSOLE PASTE CODE
1052→  // ============================================================
1053→  function generateConsoleCode() {
1054→    return "(function(){" +
1055→      "var n=localStorage.getItem('claude_lb_name');" +
1056→      "if(!n){n=prompt('Enter your leaderboard name:');if(!n)return;localStorage.setItem('claude_lb_name',n);}" +
1057→      "var t=localStorage.getItem('claude_lb_team');" +
1058→      "if(!t){t=prompt('Enter your team (NY, NC, Xyne, HS, or JP):');if(!t)return;localStorage.setItem('claude_lb_team',t);}" +
1059→      "var b=document.body.innerText,re=/(\\d{1,3})%\\s*used/g,all=[],m;" +
1060→      "while((m=re.exec(b))!==null)all.push(parseInt(m[1]));" +
1061→      "var sp=all[0]||null,wp=all[1]||null;" +
1062→      "if(!sp&&!wp){alert('No usage data found. Open claude.ai/settings/usage first.');return;}" +
1063→      // Session reset timer — only match in text before "Weekly limits" to avoid Sonnet's timer
1064→      "var sb=b.split(/Weekly limits/i)[0]||b;" +
1065→      "var sra=null,srHM=sb.match(/in\\s+(\\d+)\\s*hr?\\s+(\\d+)\\s*min/i)," +
1066→      "srM=sb.match(/in\\s+(\\d+)\\s*min/i),srH=sb.match(/in\\s+(\\d+)\\s*hr/i);" +
1067→      "if(srHM)sra=new Date(Date.now()+(parseInt(srHM[1])*3600+parseInt(srHM[2])*60)*1000).toISOString();" +
1068→      "else if(srM)sra=new Date(Date.now()+parseInt(srM[1])*60000).toISOString();" +
1069→      "else if(srH)sra=new Date(Date.now()+parseInt(srH[1])*3600000).toISOString();" +
1070→      // Weekly reset timer: "Sat 5:29 PM" pattern
1071→      "var wra=null,wrm=b.match(/(sun|mon|tue|wed|thu|fri|sat)\\w*\\s+(\\d+):(\\d+)\\s*(am|pm)/i);" +
1072→      "if(wrm){var dn=['sun','mon','tue','wed','thu','fri','sat']," +
1073→      "td=dn.indexOf(wrm[1].toLowerCase().slice(0,3)),hr=parseInt(wrm[2]),mn=parseInt(wrm[3])," +
1074→      "pm=wrm[4].toLowerCase()==='pm';if(pm&&hr!==12)hr+=12;if(!pm&&hr===12)hr=0;" +
1075→      "var nw=new Date(),rs=new Date(nw),da=(td-nw.getDay()+7)%7;" +
1076→      "if(da===0){var tt=new Date(nw);tt.setHours(hr,mn,0,0);if(tt<=nw)da=7;}" +
1077→      "rs.setDate(rs.getDate()+da);rs.setHours(hr,mn,0,0);wra=rs.toISOString();}" +
1078→      // Extra usage
1079→      "var esm=b.match(/\\$(\\d+(?:\\.\\d{1,2})?)\\s*spent/i),es=esm?parseFloat(esm[1]):null;" +
1080→      "var elm=b.match(/\\$(\\d+(?:,\\d{3})*)\\s*\\n?\\s*Monthly spend limit/i),el=elm?parseFloat(elm[1].replace(/,/g,'')):null;" +
1081→      "var ep=(esm&&all.length>=4)?all[3]:null;" +
1082→      // Confirm
1083→      "var msg='Sync as '+n+' ('+t+')?\\nSession: '+(sp||'--')+'%  Monthly: '+(wp||'--')+'%';" +
1084→      "if(es!==null)msg+='\\nExtra usage: $'+es.toFixed(2)+' spent';" +
1085→      "if(!confirm(msg))return;" +
1086→      // Detect plan type — look for 20x or 5x on page
1087→      "var pt=null;if(/\\b20\\s*[×x]\\b/i.test(b))pt='max20';else if(/\\b5\\s*[×x]\\b/i.test(b))pt='max5';" +
1088→      // Build payload — send raw values, server handles per-plan tracking
1089→      "var p={name:n,team:t,source:'console'};if(pt)p.planType=pt;if(sp!==null)p.sessionPct=sp;if(wp!==null)p.weeklyPct=wp;" +
1090→      "if(sra)p.sessionResetsAt=sra;if(wra)p.weeklyResetsAt=wra;" +
1091→      "if(es!==null)p.extraUsageSpent=es;if(el!==null)p.extraUsageLimit=el;if(ep!==null)p.extraUsagePct=ep;" +
1092→      "var ok=navigator.sendBeacon('" + API_BASE + "/api/usage',new Blob([JSON.stringify(p)],{type:'text/plain'}));" +
1093→      "if(ok)alert('Synced! '+n+' ('+t+') - Session: '+(sp||'--')+'%, Monthly: '+(wp||'--')+'%');" +
1094→      "else alert('Sync failed. Please try again.')" +
1095→      "})()";
1096→  }
