function buildRowHTML(u, i, pctKey, otherPctKey, otherLabel, sparkKey, delta) {
  const pct = effectivePct(u, pctKey);
  const otherPct = effectivePct(u, otherPctKey);
  const rank = getRank(pct);
  const pos = i + 1;
  const posClass = pos <= 3 ? 'p' + pos : 'px';
  const rowClass = pos <= 3 ? 'rank-' + pos : '';
  const barClass = getBarClass(pct);
  const barWidth = Math.min(pct, 100);
  const fire = pct >= 80 ? '<span class="fire-icon">\u{1f525}</span> ' : '';
  const ago = timeAgo(u.lastUpdated);
  const teamCls = TEAM_CSS[u.team] || 'ny';
  const rawSparkData = u[sparkKey] || [];
  const nf = planNormFactor(u);
  const sparkData = nf > 1 ? rawSparkData.map(v => v / nf) : rawSparkData;
  const sparkColor = pctColor(pct);
  const safeId = escAttr(u.id);
  const hoursAgo = u.lastUpdated ? (Date.now() - new Date(u.lastUpdated).getTime()) / 3600000 : Infinity;
  const isStale = hoursAgo > 24;
  const isInactive = hoursAgo > 72;
  const nextRank = getNextRank(pct);
  const deltaHtml = delta !== undefined && delta !== null ? `<span class="rank-delta ${delta > 0 ? 'up' : delta < 0 ? 'down' : 'same'}">${delta > 0 ? '\u2191' + delta : delta < 0 ? '\u2193' + Math.abs(delta) : '\u2014'}</span>` : '';

  return `
    <div class="lb-row clickable ${rowClass}${isStale ? ' stale' : ''}" data-uid="${safeId}" onclick="openDetail('${safeId}')">
      <div class="lb-position ${posClass}">#${pos}${deltaHtml}</div>
